class Solution:
    def numberOfPairs(self, nums1, nums2, diff):
        n = len(nums1)
        a = [nums1[i] - nums2[i] for i in range(n)]
        count = 0
        for i in range(n):
            for j in range(i + 1, n):
                if a[i] - a[j] <= diff:
                    count += 1
        return count

