var numberOfPairs = function(nums1, nums2, diff) {
    const n = nums1.length;
    const a = [];
    for (let i = 0; i < n; i++) a.push(nums1[i] - nums2[i]);
    const lowerBound = (arr, x) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) { const m = (lo + hi) >> 1; if (arr[m] < x) lo = m + 1; else hi = m; }
        return lo;
    };
    const upperBound = (arr, x) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) { const m = (lo + hi) >> 1; if (arr[m] <= x) lo = m + 1; else hi = m; }
        return lo;
    };
    const seen = [];
    let count = 0;
    for (let j = 0; j < n; j++) {
        count += upperBound(seen, a[j] + diff);
        const pos = lowerBound(seen, a[j]);
        seen.splice(pos, 0, a[j]);
    }
    return count;
};
